#!/usr/bin/env python3
"""Robust heuristic exploration planner: max-utility neighbour + global highest-utility BFS + epsilon-greedy."""
import os, sys, json, argparse, math, random
import numpy as np
from collections import deque

from cogniplan_env import ExplorationEnv


def euclidean(p1, p2):
    return math.hypot(p1[0] - p2[0], p1[1] - p2[1])


def bfs_path(start_idx, target_idx, adj):
    """BFS from start_idx to target_idx returning parent list and dist; path can be reconstructed."""
    n = len(adj)
    dist = [-1] * n
    parent = [-1] * n
    q = deque([start_idx])
    dist[start_idx] = 0
    while q:
        u = q.popleft()
        if u == target_idx:
            break
        for v in adj[u]:
            if dist[v] == -1:
                dist[v] = dist[u] + 1
                parent[v] = u
                q.append(v)
    return dist, parent


def reconstruct_path(start_idx, target_idx, parent):
    """Reconstruct node list from start to target, excluding start."""
    path = []
    curr = target_idx
    while curr != -1 and curr != start_idx:
        path.append(curr)
        curr = parent[curr]
    if curr == start_idx:
        path.reverse()
        return path
    else:
        return []  # no path


def run_episode(env, max_steps=128, epsilon=0.05):
    obs = env.reset()
    nodes = obs['nodes']
    robot_pos = (float(obs['robot_pos'][0]), float(obs['robot_pos'][1]))

    # Build static graph
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord = (n['coords'][0], n['coords'][1])
        coord_to_idx[coord] = i
    adj = [[] for _ in nodes]
    for i, n in enumerate(nodes):
        for nb_coord in n.get('neighbors', []):
            nb_key = (nb_coord[0], nb_coord[1])
            if nb_key in coord_to_idx:
                adj[i].append(coord_to_idx[nb_key])

    # Current node index
    min_d = float('inf')
    curr_idx = 0
    for coord, idx in coord_to_idx.items():
        d = euclidean(coord, robot_pos)
        if d < min_d:
            min_d = d
            curr_idx = idx

    recent = deque(maxlen=8)  # prevent immediate revisits
    recent.append(curr_idx)

    for step in range(max_steps):
        # Gather immediate neighbours and their utilities
        neighbor_coords = obs.get('neighbors', [])
        neighbor_idxs = []
        for nb in neighbor_coords:
            nb_key = (nb[0], nb[1])
            if nb_key in coord_to_idx:
                neighbor_idxs.append(coord_to_idx[nb_key])

        best_util = -1
        best_nb_idx = -1
        for ni in neighbor_idxs:
            if ni in recent:  # skip very recent nodes unless no choice
                continue
            util = nodes[ni]['utility']
            if util > best_util:
                best_util = util
                best_nb_idx = ni

        if best_util > 0:
            # If we have a high-utility neighbour, go there
            next_idx = best_nb_idx
        else:
            # No local high-utility neighbour → global planning
            # Try epsilon-greedy: random neighbour
            if random.random() < epsilon and neighbor_idxs:
                next_idx = random.choice([ni for ni in neighbor_idxs if ni not in recent] or neighbor_idxs)
            else:
                # Pick globally highest-utility node (utility > 0)
                max_util = -1
                global_best_idx = -1
                for i, n in enumerate(nodes):
                    util = n['utility']
                    if util > max_util:
                        max_util = util
                        global_best_idx = i
                if max_util > 0:
                    # BFS to that node
                    _, parent = bfs_path(curr_idx, global_best_idx, adj)
                    path = reconstruct_path(curr_idx, global_best_idx, parent)
                    if path:
                        # Next node is first step along path
                        next_idx = path[0]
                    else:
                        # Fallback: any reachable neighbour
                        if neighbor_idxs:
                            next_idx = random.choice([ni for ni in neighbor_idxs if ni not in recent] or neighbor_idxs)
                        else:
                            break
                else:
                    # No node with utility > 0 — episode should end
                    if neighbor_idxs:
                        next_idx = random.choice([ni for ni in neighbor_idxs if ni not in recent] or neighbor_idxs)
                    else:
                        break

        # Move
        target_coord = (nodes[next_idx]['coords'][0], nodes[next_idx]['coords'][1])
        obs, info = env.step(target_coord)
        curr_idx = next_idx
        recent.append(curr_idx)

        if info.get('done', False):
            break

    metrics = env.get_metrics()
    return {
        'explored_rate': float(metrics['explored_rate']),
        'travel_distance': float(metrics['travel_distance']),
        'success': bool(metrics['success']),
        'n_steps': int(metrics.get('n_steps', max_steps))
    }


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', type=str, required=True)
    parser.add_argument('--checkpoint', type=str, required=True)
    parser.add_argument('--output', type=str, required=True)
    parser.add_argument('--epsilon', type=float, default=0.05)
    args = parser.parse_args()

    eval_config_path = os.path.join(args.data_path, 'eval_config.json')
    with open(eval_config_path, 'r') as f:
        config = json.load(f)

    maps_eval = os.path.join(args.data_path, 'maps_eval')
    per_episode = []
    per_type = {}
    total_episodes = 0

    for env_type in config.get('env_types', ['room', 'tunnel', 'outdoor']):
        type_dir = os.path.join(maps_eval, env_type)
        if not os.path.isdir(type_dir):
            continue
        for map_file in sorted(os.listdir(type_dir)):
            if map_file.endswith('.png'):
                full_path = os.path.join(type_dir, map_file)
                env = ExplorationEnv(map_path=full_path)
                metrics = run_episode(env, epsilon=args.epsilon)
                per_episode.append({
                    'map_path': os.path.join(env_type, map_file),
                    'env_type': env_type,
                    'success': 1 if metrics['success'] else 0,
                    'travel_distance': metrics['travel_distance'],
                    'explored_rate': metrics['explored_rate']
                })
                total_episodes += 1
                if env_type not in per_type:
                    per_type[env_type] = {
                        'explored_rate_sum': 0.0,
                        'distance_sum': 0.0,
                        'success_count': 0,
                        'count': 0
                    }
                per_type[env_type]['explored_rate_sum'] += metrics['explored_rate']
                per_type[env_type]['distance_sum'] += metrics['travel_distance'] if metrics['success'] else 0.0
                if metrics['success']:
                    per_type[env_type]['success_count'] += 1
                per_type[env_type]['count'] += 1

    # Aggregate
    explored_rates = [e['explored_rate'] for e in per_episode]
    success_count = sum(e['success'] for e in per_episode)
    successful_distances = [e['travel_distance'] for e in per_episode if e['success'] == 1]
    avg_explored = sum(explored_rates) / len(per_episode) if per_episode else 0.0
    avg_distance = sum(successful_distances) / len(successful_distances) if successful_distances else 0.0
    success_rate = success_count / len(per_episode) if per_episode else 0.0

    per_type_out = {}
    for env_type, stats in per_type.items():
        cnt = stats['count']
        per_type_out[env_type] = {
            'explored_rate': stats['explored_rate_sum'] / cnt,
            'travel_distance': stats['distance_sum'] / stats['success_count'] if stats['success_count'] > 0 else 0.0,
            'success_rate': stats['success_count'] / cnt
        }

    output = {
        'explored_rate': avg_explored,
        'travel_distance': avg_distance,
        'success_rate': success_rate,
        'per_episode': per_episode,
        'per_type': per_type_out,
        'total_episodes': total_episodes
    }

    with open(args.output, 'w') as f:
        json.dump(output, f, indent=2)


if __name__ == '__main__':
    main()
